import{_ as a}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as r,c as e,e as t}from"./app.19f78461.js";const h={},i=t('<h2 id="前言" tabindex="-1"><a class="header-anchor" href="#前言" aria-hidden="true">#</a> 前言</h2><p>《你不知道的 JavaScript》 是一部由 Kyle Simpson 所著的 JavaScript 书籍。这本书旨在深入探讨 JavaScript 语言的核心概念，特别是一些常常被开发者误解或忽视的部分。</p><p>这本书是一本深入研究 JavaScript 的经典之作，对于想要提高他们的 JavaScript 编程技能的开发者来说是一本非常有价值的资源，可以帮助你更深入地理解 JavaScript 的内部工作原理。</p><h2 id="推荐理由" tabindex="-1"><a class="header-anchor" href="#推荐理由" aria-hidden="true">#</a> 推荐理由</h2><p>《你不知道的 JavaScript》 是我看完 《JavaScript 高级程序设计》 后看的第二部前端书籍，总共分为上、中、下三卷，每一卷都能带给我新的收获。其中内容深入的讲解了前端开发过程中可能不了解但应该掌握的基本知识，让我受益匪浅。像上卷中的 <strong>作用域</strong> 部分、中卷中的 <strong>异步与性能部分</strong> 都让我对于项目中 JS 的行为有了更深刻的认识。</p><p>同时它也是第一部我读得入迷的前端书籍，其中的一些概念让我感到有趣。像 <strong>JS 编译</strong>、<strong>词法作用域</strong>，以及生成器和 Promise 结合产生的 <strong>异步函数</strong>，这些无不让我感叹前人的智慧。</p><h2 id="第一部分-作用域和闭包" tabindex="-1"><a class="header-anchor" href="#第一部分-作用域和闭包" aria-hidden="true">#</a> 第一部分 作用域和闭包</h2><h3 id="第-1-章-作用域是什么" tabindex="-1"><a class="header-anchor" href="#第-1-章-作用域是什么" aria-hidden="true">#</a> 第 1 章 作用域是什么</h3><p>本章讲述了有关作用域相关的知识，从编译原理开始，一步一步了解作用域的本质，还介绍了与作用域相关的 LHS、RHS 查询。</p><h3 id="第-2-章-词法作用域" tabindex="-1"><a class="header-anchor" href="#第-2-章-词法作用域" aria-hidden="true">#</a> 第 2 章 词法作用域</h3><p>第 1 章讲述了什么是作用域，第 2 章则带我们了解作用域两种工作模型的其中一种：词法作用域。其中讲述了词法作用域的基本概念，以及词法作用域中数据的查找方式，最后介绍了如何欺骗词法以及欺骗词法所带来的性能问题。</p><h3 id="第-3-章-函数作用域和块作用域" tabindex="-1"><a class="header-anchor" href="#第-3-章-函数作用域和块作用域" aria-hidden="true">#</a> 第 3 章 函数作用域和块作用域</h3><p>这一章介绍了函数作用域和块作用域的概念，同时还介绍了函数作用域如何隐藏其内部实现、规避代码冲突，以及函数的一些有趣特性：匿名函数和具名函数、立即执行表达式。最后讲解了块作用域的相关知识，以及他带来的一些好处。</p><h3 id="第-4-章-提升" tabindex="-1"><a class="header-anchor" href="#第-4-章-提升" aria-hidden="true">#</a> 第 4 章 提升</h3><p>本章讲解了 JavaScript 世界中的独特特性：提升。本章内容描述了编译器进入一个新的作用域时是如何工作的，即提升的原理是什么。</p><h3 id="第-5-章-作用域闭包" tabindex="-1"><a class="header-anchor" href="#第-5-章-作用域闭包" aria-hidden="true">#</a> 第 5 章 作用域闭包</h3><p>本章带我们理解 JS 中最重要的概念之一：闭包。内容讲述了闭包是什么，闭包是如何产生及工作的，还扩展了很多与闭包相关的知识，比如模块。</p>',17),n=[i];function d(o,s){return r(),e("div",null,n)}const _=a(h,[["render",d],["__file","you_don't_know_js.html.vue"]]);export{_ as default};
